def process(list, fieldName, fieldValue):
    """Remove first struct/dict from list where field matches value"""
    if not list or not isinstance(list, (list, tuple)):
        return [], None, False
    field = str(fieldName or '')
    result = []
    removed = None
    found = False
    for item in list:
        if not found and isinstance(item, dict) and field in item:
            if item[field] == fieldValue:
                removed = item
                found = True
                continue
        result.append(item)
    return result, removed, found
